data.query:
query Bites($mine: Boolean, $transcript_id: ID, $my_team: Boolean, $limit: Int, $skip: Int) {
    bites(mine: $mine, transcript_id: $transcript_id, my_team: $my_team, limit: $limit, skip: $skip) {
        id
        name
        transcript_id
        start_time
        end_time
        status
        summary
        user_id
        user {
            id
            name
            first_name
            last_name
            picture
        }
        created_at
    }
}
